import 'package:flutter/material.dart';
import 'package:get/get.dart';

void main() => runApp(MyApp());

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return GetMaterialApp(
      home: DialogDemo(),
    );
  }
}

class DialogDemo extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('GetX Dialog Demo')),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            ElevatedButton(
              onPressed: () {
                Get.defaultDialog(
                  title: 'Alert',
                  middleText: 'This is a default dialog',
                  textConfirm: 'OK',
                  textCancel: 'Cancel',
                  onConfirm: () {
                    Get.back();
                    Get.snackbar('Confirmed', 'You pressed OK');
                  },
                  onCancel: () => Get.back(),
                );
              },
              child: Text('Default Dialog'),
            ),
            ElevatedButton(
              onPressed: () async {
                final result = await Get.dialog(
                  AlertDialog(
                    title: Text('Confirm'),
                    content: Text('Are you sure?'),
                    actions: [
                      TextButton(
                        onPressed: () => Get.back(result: false),
                        child: Text('No'),
                      ),
                      TextButton(
                        onPressed: () => Get.back(result: true),
                        child: Text('Yes'),
                      ),
                    ],
                  ),
                );
                if (result == true) {
                  Get.snackbar('Confirmed', 'You said yes');
                } else if (result == false) {
                  Get.snackbar('Cancelled', 'You said no');
                }
              },
              child: Text('Dialog with Result'),
            ),
            ElevatedButton(
              onPressed: () {
                Get.dialog(
                  Center(
                    child: Container(
                      width: 250,
                      padding: EdgeInsets.all(20),
                      decoration: BoxDecoration(
                        color: Colors.white,
                        borderRadius: BorderRadius.circular(16),
                      ),
                      child: Column(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          Icon(Icons.star, size: 50, color: Colors.orange),
                          SizedBox(height: 10),
                          Text('Custom Dialog', style: TextStyle(fontSize: 18)),
                          SizedBox(height: 20),
                          ElevatedButton(
                            onPressed: () => Get.back(),
                            child: Text('Close'),
                          ),
                        ],
                      ),
                    ),
                  ),
                  barrierDismissible: false,
                );
              },
              child: Text('Custom Dialog'),
            ),
          ],
        ),
      ),
    );
  }
}
